"use strict";(self.webpackChunkagentico_dev=self.webpackChunkagentico_dev||[]).push([[8130],{7735:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/ollama-run-deepseek-on-docker","metadata":{"permalink":"/blog/ollama-run-deepseek-on-docker","source":"@site/blog/ollama-run-deepseek-on-docker/index.mdx","title":"Run DeepSeek-R1 locally with Ollama on Docker","description":"Would you like to run local LLMs, here is how you can do it with Ollama and the new DeepSeek-R1 model.","date":"2025-01-30T13:19:59.000Z","tags":[{"inline":false,"label":"Ollama","permalink":"/blog/tags/ollama","description":"Get up and running with large language models locally."},{"inline":false,"label":"LLM","permalink":"/blog/tags/llm","description":"Large Language Models (LLM) are AI models that are trained on large amounts of text data to generate human-like text."},{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker is a platform for developing, shipping, and running applications in containers."},{"inline":false,"label":"AI","permalink":"/blog/tags/ai","description":"Artificial Intelligence (AI) is a field of computer science that aims to create machines that can perform tasks that typically require human intelligence."}],"readingTime":1.395,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Run DeepSeek-R1 locally with Ollama on Docker","description":"Would you like to run local LLMs, here is how you can do it with Ollama and the new DeepSeek-R1 model.","image":"./deepseek-docker-sq.png","tags":["ollama","llm","docker","ai"],"keywords":["ollama","llm","docker","ai","deepseek"]},"unlisted":false},"content":"<head>\\n  <link rel=\\"canonical\\" href=\\"https://www.linkedin.com/pulse/run-deepseek-r1-locally-ollama-docker-adrian-escutia-wtikc\\" />\\n</head>\\n\\nWould you like to run local LLMs, here is how you can do it with [Ollama](https://ollama.com/) and the new [DeepSeek](https://www.deepseek.com/)-R1 model that is breaking the boundaries of AI. \ud83d\ude80\\n\\nFor those of us passionate about pushing the boundaries of AI, this is a game changer. \ud83d\udca1 \\n\\n\x3c!-- truncate --\x3e\\n\\nBeing able to run powerful language models locally, with the flexibility to fine-tune and experiment in a more personalized and secure environment, opens up so many possibilities. \\n\\n## What is Ollama?\\n\\nOllama is a tool that allows you to run LLMs locally, securely, and efficiently. It is a powerful tool that allows you to run LLMs in a Docker container, and it is designed to be easy to use and flexible.\\n\\n## What is DeepSeek-R1?\\n\\nDeepSeek-R1 is a powerful language model that is designed to be easy to use and flexible. It is a model that is designed to be able to understand and generate human-like text, and it is trained on a large dataset of text from the internet.\\n\\n## How to run DeepSeek-R1 locally with Ollama on Docker?\\n\\nSteps to run [DeepSeek AI](https://github.com/deepseek-ai/DeepSeek-LLM) locally with [Ollama](https://ollama.com) on Docker:\\n\\n```bash\\n# Install Ollama\\ndocker run -d -v ollama:/root/.ollama -p 11434:11434 --name ollama ollama/ollama\\n# Pull the DeepSeek-R1 model\\ndocker exec -it ollama ollama run deepseek-r1:7b\\n# Start chatting with DeepSeek-R1 - Web UI\\ndocker run -d -p 3000:8080 --add-host=host.docker.internal:host-gateway -v open-webui:/app/backend/data --name open-webui --restart always ghcr.io/open-webui/open-webui:main\\n```\\n\\nOpen http://localhost:3000 in your browser, and you are done!\\n\\nLet\'s make AI work for us, locally, efficiently, and creatively! \ud83d\udca5\\n\\n## Step by step screenshots\\n\\n![Step by step](./ezgif.com-animated-gif-maker.gif)\\n\\nGIF generated with [ezgic.com](https://ezgif.com/). \ud83c\udfa8\\n\\nGo Rebels! \u270a\ud83c\udffb"}]}}')}}]);